import axios from 'axios';

const api = axios.create({ baseURL: '/api' });

export const getApps = (category) =>
  api.get('/apps', { params: category ? { category } : {} }).then(r => r.data);

export const getCategories = () =>
  api.get('/apps/categories').then(r => r.data);

export const getInstalledApps = () =>
  api.get('/installed').then(r => r.data);

export const installApp = (appId) =>
  api.post('/install', { app_id: appId }).then(r => r.data);

export const uninstallApp = (appId) =>
  api.delete('/uninstall', { data: { app_id: appId } }).then(r => r.data);

export const runApp = (appName, args = {}) =>
  api.post(`/run/${appName}`, args).then(r => r.data);

export const getHistory = () =>
  api.get('/history').then(r => r.data);
